ity();				}			});								}		else		{			$("#lbl_req_coupon").css("display","none").html("");			<?php			if(date("Y-m-d")<=$date_range_earlybirddiscount)			{			?>			early_bird_discount = $("#early_bird_discount").val();			//promotion_amount = parseFloat(total_amount)*parseFloat(early_bird_discount)/parseFloat(100);			//total_amount = parseFloat(total_amount)-parseFloat(promotion_amount);			total_amount = parseFloat(total_amount)-parseFloat(early_bird_discount);			$("#early_bird_discountfields").show();			$("#promotion_amount").val(early_bird_discount);			$("#net_amount").val(total_amount)			<?php			}			?>		}}</script><style>#freetrial .lable {	float:left;	display:block;	width:180px;	height:20px;	margin-top:10px;	margin-right:10px;	color:#395057;	font-family:Arial, Helvetica, sans-serif;	font-size:12px;}#h1 {	padding:5px;	font-family:Verdana, Arial, Helvetica, sans-serif;	font-size:18px;	color:#1b556e;	margin-bottom:10px;	padding-left:28px;}.h2 {		font-family:Verdana, Arial, Helvetica, sans-serif;	font-size:14px;	color:#1b556e;	padding-bottom:10px;	}.contactus{	width:758px;	float:right;	color: #000000;    font-family: Verdana,Arial,Helvetica,sans-serif;	font-size:12px;}.txtbox{	background-image: url("images/inputbox.png");    background-repeat: no-repeat;    border: medium none;    color: #000;    font-family: Arial,Helvetica,sans-serif;    font-size: 12px;    height: 25px;    padding: 8px 10px;    width: 270px;}.selectbox{	background-image: url("images/inputbox.png");    background-repeat: no-repeat;    border: medium none;    color: #000;    font-family: Arial,Helvetica,sans-serif;    font-size: 12px;    height: 40px;    padding: 8px 1